import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is cash flow in rental property?", a: "Cash flow is rental income left after vacancy, mortgage payment, taxes, insurance, maintenance, management, and other expenses." },
  { q: "What is cap rate?", a: "Cap rate is net operating income divided by property value. It measures property return before financing." },
  { q: "What is a good ROI on rental property?", a: "A good ROI depends on market, risk, financing, appreciation, and management needs. Investors often compare ROI with other available investments." },
  { q: "What is cash-on-cash return?", a: "Cash-on-cash return compares annual cash flow to the actual cash invested, such as down payment and upfront costs." },
  { q: "What is the 1% rule in rental property?", a: "The 1% rule says monthly rent near 1% of purchase price may be worth a closer look, but it is only a rough screening shortcut." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const pct = (v: number) => `${Number.isFinite(v) ? v.toFixed(2) : "0.00"}%`;
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
function payment(principal: number, apr: number, years = 30) { const r = apr / 100 / 12; const n = years * 12; return r === 0 ? principal / n : principal * r / (1 - Math.pow(1 + r, -n)); }
function metrics(price: number, down: number, rate: number, rent: number, vacancy: number, tax: number, insurance: number, maintenance: number, management: number) {
  const loan = Math.max(0, price - down);
  const mortgage = payment(loan, rate);
  const effectiveRent = rent * (1 - vacancy / 100);
  const monthlyExpenses = mortgage + tax / 12 + insurance / 12 + maintenance + rent * management / 100;
  const cashFlow = effectiveRent - monthlyExpenses;
  const noi = (effectiveRent - tax / 12 - insurance / 12 - maintenance - rent * management / 100) * 12;
  const cashInvested = Math.max(1, down);
  return { cashFlow, annualRoi: cashFlow * 12 / cashInvested * 100, capRate: noi / price * 100, coc: cashFlow * 12 / cashInvested * 100, grm: price / (rent * 12) };
}

export default function RentalPropertyCalculator() {
  useCurrencyVersion();
  const [price, setPrice] = useState(300000);
  const [down, setDown] = useState(60000);
  const [rate, setRate] = useState(6.5);
  const [rent, setRent] = useState(2800);
  const [vacancy, setVacancy] = useState(8);
  const [tax, setTax] = useState(3600);
  const [insurance, setInsurance] = useState(1400);
  const [maintenance, setMaintenance] = useState(250);
  const [management, setManagement] = useState(8);
  const result = useMemo(() => metrics(price, down, rate, rent, vacancy, tax, insurance, maintenance, management), [price, down, rate, rent, vacancy, tax, insurance, maintenance, management]);
  const scenarios = [["Conservative (5% vacancy)", 5], ["Moderate (8% vacancy)", 8], ["Aggressive (12% vacancy)", 12]] as const;
  const example = scenarios.map(([, v]) => metrics(300000, 60000, 6.5, 2800, v, 3600, 1400, 250, 8));
  const rows = [
    ["Monthly Cash Flow", example.map((x) => money(x.cashFlow)), "Income left after monthly expenses"],
    ["Annual ROI", example.map((x) => pct(x.annualRoi)), "Annual cash flow divided by cash invested"],
    ["Cap Rate", example.map((x) => pct(x.capRate)), "NOI divided by property value"],
    ["Cash-on-Cash", example.map((x) => pct(x.coc)), "Cash flow return on invested cash"],
    ["GRM", example.map((x) => x.grm.toFixed(2)), "Price divided by annual gross rent"],
  ];
  return (
    <>
      <SEOHead title="Free Rental Property Calculator Online - Calculate Rental ROI and Cash Flow Instantly | CalcHive" description="Free online rental property calculator. Calculate monthly cash flow, ROI, cap rate and cash-on-cash return for any rental property investment instantly. 100% free, no signup required." canonical="/rental-property-calculator" keywords="free rental property calculator, rental property ROI calculator free online, cash flow rental calculator free, cap rate calculator free, real estate investment calculator free" category="Financial Calculators" breadcrumbName="Free Rental Property Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Rental Property Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate rental cash flow, ROI, cap rate, cash-on-cash return, and gross rent multiplier.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">{[["Purchase price", price, setPrice], ["Down payment", down, setDown], ["Mortgage rate (%)", rate, setRate], ["Monthly rental income", rent, setRent], ["Vacancy rate (%)", vacancy, setVacancy], ["Annual property tax", tax, setTax], ["Annual insurance", insurance, setInsurance], ["Monthly maintenance", maintenance, setMaintenance], ["Management fee (%)", management, setManagement]].map(([label, value, setter]) => <div key={String(label)}><label className="text-sm font-semibold text-foreground block mb-2">{String(label)}</label><input type="number" value={Number(value)} onChange={(e) => (setter as (v: number) => void)(Number(e.target.value))} className={inputClass} /></div>)}</div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Cash Flow</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.cashFlow)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-4 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Annual ROI</p><p className="text-lg font-extrabold text-foreground">{pct(result.annualRoi)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Cap rate</p><p className="text-lg font-extrabold text-foreground">{pct(result.capRate)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Cash-on-cash</p><p className="text-lg font-extrabold text-foreground">{pct(result.coc)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">GRM</p><p className="text-lg font-extrabold text-foreground">{result.grm.toFixed(2)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Rental Property ROI and Cash Flow for Free</h2><p className="text-muted-foreground leading-relaxed">Subtract mortgage and operating costs from effective rental income, then compare annual return to your cash invested.</p><h2 className="text-2xl font-bold text-foreground">Key Metrics Every Rental Property Investor Needs to Know</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Rental Property Investment Metrics - $300,000 Property</caption><thead className="bg-muted/60"><tr>{["Metric", "Conservative (5% vacancy)", "Moderate (8% vacancy)", "Aggressive (12% vacancy)", "What It Means"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map(([metric, vals, meaning]) => <tr key={String(metric)}><td className="py-2.5 px-3 font-semibold">{String(metric)}</td>{(vals as string[]).map((v) => <td key={v} className="py-2.5 px-3">{v}</td>)}<td className="py-2.5 px-3">{String(meaning)}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Real Estate Investment Calculator for Everyone</h2><p className="text-muted-foreground leading-relaxed">Use this rental calculator to screen properties before deeper due diligence, financing quotes, and local market research.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/rental-property-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


